const variables = automaRefData('variables', '');
const targetCodeType = variables.select_code_type;
const rows = Array.from(document.querySelectorAll('.codebook-table .ant-table-tbody > tr.ant-table-row'));
const targetRow = rows.find(tr => tr.querySelector('td:nth-child(1) span')?.innerText.trim() === targetCodeType);
if (targetRow) {
  targetRow.click();
  setTimeout(() => automaNextBlock(), 1000);
} else {
  console.error('Code Type not found');
  automaNextBlock();
}
